+    #[test]
+    fn config_serde_roundtrip() {
+        let config = Config {
+            theme: Some("dark".to_string()),
+            default_provider: Some("anthropic".to_string()),
+            compaction: Some(super::CompactionSettings {
+                enabled: Some(true),
+                reserve_tokens: Some(1000),
